using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── CalculateTotal: DataRow-driven tests ──────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.05, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: invalid-input tests ───────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative unit price")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity")]
    [DataRow(10.00, 1, -0.01, "taxRate", DisplayName = "Tax rate below 0")]
    [DataRow(10.00, 1, 1.01, "taxRate", DisplayName = "Tax rate above 1")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // ── ApplyDiscount: DynamicData-driven tests ───────────────────────

    public static IEnumerable<object[]> DiscountCases
    {
        get
        {
            yield return [200.00m, 0m, 200.00m, "No discount"];
            yield return [200.00m, 10m, 180.00m, "10% off"];
            yield return [200.00m, 50m, 100.00m, "Half price"];
            yield return [200.00m, 100m, 0.00m, "100% discount (free)"];
            yield return [49.99m, 25m, 37.4925m, "Fractional result"];
            yield return [0.00m, 50m, 0.00m, "Zero price with discount"];
        }
    }

    [TestMethod]
    [DynamicData(nameof(DiscountCases), DynamicDataDisplayName = nameof(GetDiscountDisplayName))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected, string _)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static string GetDiscountDisplayName(MethodInfo _, object[] data) => (string)data[3];

    // ── ApplyDiscount: boundary / invalid ─────────────────────────────

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Discount below 0")]
    [DataRow(100.01, DisplayName = "Discount above 100")]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // ── FormatPrice: DataRow-driven tests ─────────────────────────────

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Dollar formatting")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro formatting")]
    [DataRow(1000.5, "$", "$1000.50", DisplayName = "Trailing zero padded")]
    [DataRow(0.0, "£", "£0.00", DisplayName = "Zero price")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

